#!/usr/bin/env python3
"""
A simple static site generator that converts Markdown files to HTML pages.
Place your Markdown files in a 'content' folder and provide a 'template.html'
file in the working directory. The generated HTML files will be saved into an 'output' folder.

Usage:
    python static_site_generator.py
"""

import os
import sys
import glob
import markdown

CONTENT_DIR = "content"
OUTPUT_DIR = "output"
TEMPLATE_FILE = "template.html"
CONTENT_PLACEHOLDER = "{{ content }}"  # placeholder inside template

def load_template(template_path):
    try:
        with open(template_path, "r", encoding="utf-8") as f:
            return f.read()
    except FileNotFoundError:
        sys.exit(f"Template file '{template_path}' not found.")

def convert_markdown_to_html(md_text):
    return markdown.markdown(md_text)

def render_page(template, content_html):
    return template.replace(CONTENT_PLACEHOLDER, content_html)

def build_site():
    # Ensure output directory exists.
    if not os.path.exists(OUTPUT_DIR):
        os.makedirs(OUTPUT_DIR)

    # Load template.
    template = load_template(TEMPLATE_FILE)

    # Process each Markdown file in the content directory.
    md_files = glob.glob(os.path.join(CONTENT_DIR, "*.md"))
    if not md_files:
        print(f"No Markdown files found in {CONTENT_DIR} directory.")
        return

    for md_file in md_files:
        try:
            with open(md_file, "r", encoding="utf-8") as f:
                md_text = f.read()
        except Exception as e:
            print(f"Error reading {md_file}: {e}")
            continue

        # Convert markdown to HTML.
        content_html = convert_markdown_to_html(md_text)
        # Render the complete page using the template.
        full_page = render_page(template, content_html)
        # Determine output file name.
        base_name = os.path.basename(md_file)
        file_name, _ = os.path.splitext(base_name)
        output_path = os.path.join(OUTPUT_DIR, file_name + ".html")
        try:
            with open(output_path, "w", encoding="utf-8") as f:
                f.write(full_page)
            print(f"Generated {output_path}")
        except Exception as e:
            print(f"Error writing {output_path}: {e}")

if __name__ == "__main__":
    build_site()

