"""
Simple Static Site Generator: Converts Markdown files to HTML pages using a template.
Usage:
    python ssg.py --source ./content --output ./site --template template.html
Requirements:
    pip install markdown
"""

import os
import argparse
import markdown
from pathlib import Path

def parse_args():
    parser = argparse.ArgumentParser(
        description="Simple Static Site Generator: Convert Markdown files to HTML using a template"
    )
    parser.add_argument('--source', required=True, help='Directory containing Markdown files')
    parser.add_argument('--output', required=True, help='Directory to save generated HTML files')
    parser.add_argument('--template', required=True, help='HTML template file (should contain "{{ content }}" placeholder)')
    return parser.parse_args()

def load_template(template_path):
    try:
        with open(template_path, 'r', encoding='utf-8') as f:
            return f.read()
    except IOError as e:
        print("Error reading template file:", e)
        exit(1)

def convert_markdown_to_html(markdown_text):
    return markdown.markdown(markdown_text)

def generate_html(markdown_file_path, template):
    try:
        with open(markdown_file_path, 'r', encoding='utf-8') as f:
            md_content = f.read()
    except IOError as e:
        print(f"Error reading markdown file '{markdown_file_path}': {e}")
        return None

    html_content = convert_markdown_to_html(md_content)
    # Insert the converted HTML into the template where the placeholder is.
    html_page = template.replace("{{ content }}", html_content)
    return html_page

def write_output(html_content, output_path):
    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    try:
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(html_content)
        print(f"Generated: {output_path}")
    except IOError as e:
        print("Error writing HTML file:", e)

def main():
    args = parse_args()
    source_dir = Path(args.source)
    output_dir = Path(args.output)

    if not source_dir.exists() or not source_dir.is_dir():
        print(f"Source directory '{source_dir}' does not exist or is not a directory.")
        exit(1)

    template = load_template(args.template)

    # Process all Markdown files in the source directory.
    md_files = list(source_dir.glob('*.md'))
    if not md_files:
        print(f"No Markdown files found in {source_dir}")
