This script converts Markdown files into HTML pages using a simple template system.
Usage:
    python ssg.py --input-dir content --output-dir output --template template.html
"""

import argparse
import os
import sys
from pathlib import Path

try:
    import markdown
except ImportError:
    sys.exit("Please install the markdown package: pip install markdown")

def parse_args():
    parser = argparse.ArgumentParser(description="Static Site Generator")
    parser.add_argument("--input-dir", required=True, help="Directory containing Markdown files.")
    parser.add_argument("--output-dir", required=True, help="Directory to write generated HTML files.")
    parser.add_argument("--template", required=True, help="HTML template file with a '{{content}}' placeholder.")
    return parser.parse_args()

def load_template(template_path):
    with open(template_path, encoding="utf-8") as f:
        return f.read()

def convert_markdown_to_html(markdown_text):
    return markdown.markdown(markdown_text, extensions=['extra', 'codehilite'])

def render_page(template, content_html):
    # Replace the placeholder '{{content}}' in the template with the generated HTML content.
    return template.replace("{{content}}", content_html)

def process_markdown_file(md_file_path, template, output_dir):
    with open(md_file_path, encoding="utf-8") as f:
        md_content = f.read()

    # Convert markdown content to HTML.
    content_html = convert_markdown_to_html(md_content)
    # Apply template.
    full_html = render_page(template, content_html)

    # Define the output HTML file path.
    output_file = output_dir / (md_file_path.stem + ".html")
    with open(output_file, "w", encoding="utf-8") as f:
        f.write(full_html)
    print(f"Generated: {output_file}")

def main():
    args = parse_args()

    input_dir = Path(args.input_dir)
    output_dir = Path(args.output_dir)
    template_path = Path(args.template)

    if not input_dir.is_dir():
        sys.exit(f"Input directory '{input_dir}' does not exist.")
    if not template_path.is_file():
        sys.exit(f"Template file '{template_path}' does not exist.")
    output_dir.mkdir(parents=True, exist_ok=True)

    template = load_template(template_path)

    # Process all Markdown files in the input directory.
    md_files = list(input_dir.glob("*.md"))
    if not md_files:
        sys.exit(f"No Markdown files found in '{input_dir}'.")

    for md_file in md_files:
        process_markdown_file(md_file, template, output_dir)

if __name__ == "__main__":
    main()

