            self.metadata = {}


class FrontMatterParser:
    """Parses YAML front matter from markdown files."""

    FRONT_MATTER_REGEX = re.compile(r'^---\s*\n(.*?)\n---\s*\n', re.DOTALL)

    @classmethod
    def parse(cls, content: str) -> tuple[Dict[str, str], str]:
        """Parse front matter and return metadata dict and remaining content."""
        match = cls.FRONT_MATTER_REGEX.match(content)

        if not match:
            return {}, content

        front_matter = match.group(1)
        remaining_content = content[match.end():]

        metadata = {}
        for line in front_matter.split('\n'):
            if ':' in line:
                key, value = line.split(':', 1)
                metadata[key.strip()] = value.strip().strip('"\'')

        return metadata, remaining_content


