"""

import os
import re
import shutil
from pathlib import Path
from typing import Dict, Any, Optional
from datetime import datetime
import markdown
from jinja2 import Environment, FileSystemLoader, Template


class FrontMatterParser:
    """Parses YAML-like front matter from markdown files."""

    @staticmethod
    def parse(content: str) -> tuple[Dict[str, Any], str]:
        """Parse front matter and return metadata dict and remaining content."""
        if not content.startswith('---'):
            return {}, content

        try:
            _, front_matter, markdown_content = content.split('---', 2)
            metadata = {}

            for line in front_matter.strip().split('\n'):
                if ':' in line:
                    key, value = line.split(':', 1)
                    key = key.strip()
                    value = value.strip().strip('"\'')

                    # Try to convert to appropriate type
                    if value.lower() in ('true', 'false'):
                        metadata[key] = value.lower() == 'true'
                    elif value.isdigit():
                        metadata[key] = int(value)
                    else:
                        metadata[key] = value

            return metadata, markdown_content.strip()
        except ValueError:
            return {}, content


class MarkdownProcessor:
    """Processes markdown files with extensions."""

    def __init__(self):
        self.md = markdown.Markdown(
            extensions=['meta', 'codehilite', 'toc', 'tables', 'fenced_code']
        )

    def process(self, content: str) -> tuple[str, Dict[str, Any]]:
        """Convert markdown to HTML and extract metadata."""
        html = self.md.convert(content)
        metadata = getattr(self.md, 'Meta', {})

        # Flatten metadata lists (markdown.Meta returns lists)
        for key, value in metadata.items():
            if isinstance(value, list) and len(value) == 1:
                metadata[key] = value[0]

        self.md.reset()
        return html, metadata


class TemplateEngine:
    """Handles Jinja2 template rendering."""

