class FrontMatterParser:
    """Parse YAML front matter from markdown files."""

    @staticmethod
    def parse(content: str) -> tuple[Dict[str, Any], str]:
        """Extract front matter and content from markdown string."""
        if not content.startswith('---'):
            return {}, content

        try:
            _, front_matter, markdown_content = content.split('---', 2)
            metadata = yaml.safe_load(front_matter.strip()) or {}
            return metadata, markdown_content.strip()
        except ValueError:
            return {}, content


class TemplateEngine:
    """Handle template rendering with Jinja2."""

    def __init__(self, template_dir: Path):
        self.template_dir = template_dir
        self.env = Environment(
            loader=FileSystemLoader(str(template_dir)),
            autoescape=True
        )

    def render(self, template_name: str, context: Dict[str, Any]) -> str:
        """Render template with given context."""
        template = self.env.get_template(template_name)
        return template.render(**context)


class MarkdownProcessor:
    """Process markdown files and convert to HTML."""

    def __init__(self):
        self.md = markdown.Markdown(
            extensions=['meta', 'codehilite', 'toc', 'tables', 'fenced_code']
        )

    def process(self, content: str) -> tuple[str, Dict[str, Any]]:
        """Convert markdown to HTML and extract metadata."""
        html = self.md.convert(content)
        metadata = getattr(self.md, 'Meta', {})

        # Convert metadata lists to single values where appropriate
        processed_meta = {}
        for key, value in metadata.items():
